This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i1 @and_icmp_ne_and_pow2_commute(i32 %x) {
  %and = and i32 %x, -32
  %icmp1 = icmp ne i32 %and, 128
  %icmp2 = icmp ne i32 %x, 127
  %ret = and i1 %icmp1, %icmp2
  ret i1 %ret
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i1 @and_icmp_ne_and_pow2_commute(i32 %x) {
  %1 = add i32 %x, -160
  %ret = icmp ult i32 %1, -33
  ret i1 %ret
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp:InstCombinerImpl::foldAndOrOfICmpsUsingRanges to implement the missed optimization:
```cpp
    return nullptr;

  // Look through add of a constant offset on V1, V2, or both operands. This
  // allows us to interpret the V + C' < C'' range idiom into a proper range.
  const APInt *Offset1 = nullptr, *Offset2 = nullptr;
  if (V1 != V2) {
    Value *X;
    if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
      V1 = X;
    if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
      V2 = X;
